"use client"

import * as React from "react"
import type { UseQueryResult } from "@tanstack/react-query"

import type { SearchField } from "@/components/search-bar"
import type {
  DatoolCollectionQueryDefinition,
  DatoolEntityQueryDefinition,
  DatoolInstance,
  DatoolQueryDefinition,
  DatoolQuerySearch,
  DatoolSliceApi,
  DatoolStateShape,
} from "./types"

type DatoolSearchSourceValue = {
  fields: SearchField<any>[]
  signature: string
}

type DatoolStore<TState extends DatoolStateShape> = {
  getInitialState: () => TState
  getState: () => TState
  setSlice: (
    key: Extract<keyof TState, string>,
    update:
      | Partial<TState[Extract<keyof TState, string>]>
      | ((
          current: TState[Extract<keyof TState, string>]
        ) =>
          | Partial<TState[Extract<keyof TState, string>]>
          | TState[Extract<keyof TState, string>])
  ) => void
  subscribe: (listener: () => void) => () => void
}

type InternalDatoolInstance<TState extends DatoolStateShape> =
  DatoolInstance<TState> & {
    __getDefinitions: () => Record<string, DatoolQueryDefinition<any, any, any, any>>
  }

type DatoolContextValue = {
  datool: InternalDatoolInstance<any>
  resetView: (queryId: string) => void
  searchSourceByQueryId: Record<string, DatoolSearchSourceValue | undefined>
  clearSearchSource: (queryId: string) => void
  setSearchSource: (
    queryId: string,
    source: DatoolSearchSourceValue
  ) => void
  viewRevisionByQueryId: Record<string, number>
}

export type DatoolQueryValue<
  TData = unknown,
  TFilters extends Record<string, unknown> = Record<string, unknown>,
  TState extends DatoolStateShape = DatoolStateShape,
  TRow extends Record<string, unknown> = Record<string, unknown>,
> = {
  datool: DatoolInstance<TState>
  definition: DatoolQueryDefinition<TData, TFilters, TState, TRow>
  filters: TFilters
  id: string
  resetView: () => void
  result: UseQueryResult<TData>
  rows: TRow[]
  state: DatoolSliceApi<TFilters>
  viewRevision: number
}

export type DatoolProviderProps = {
  children: React.ReactNode
  datool: DatoolInstance<any>
}

function cloneState<TState extends DatoolStateShape>(state: TState) {
  return Object.fromEntries(
    Object.entries(state).map(([key, value]) => [key, { ...value }])
  ) as TState
}

function shallowEqualObjects(
  left: Record<string, unknown>,
  right: Record<string, unknown>
) {
  if (left === right) {
    return true
  }

  const leftKeys = Object.keys(left)
  const rightKeys = Object.keys(right)

  if (leftKeys.length !== rightKeys.length) {
    return false
  }

  return leftKeys.every((key) => Object.is(left[key], right[key]))
}

function createDatoolStore<TState extends DatoolStateShape>(
  initialState: TState
): DatoolStore<TState> {
  const initialSnapshot = cloneState(initialState)
  const listeners = new Set<() => void>()
  let state = cloneState(initialState)

  return {
    getInitialState: () => initialSnapshot,
    getState: () => state,
    setSlice: (key, update) => {
      const currentSlice = state[key]
      const nextPatch =
        typeof update === "function" ? update(currentSlice) : update
      const nextSlice = {
        ...currentSlice,
        ...nextPatch,
      }

      if (shallowEqualObjects(currentSlice, nextSlice)) {
        return
      }

      state = {
        ...state,
        [key]: nextSlice,
      }

      listeners.forEach((listener) => listener())
    },
    subscribe: (listener) => {
      listeners.add(listener)

      return () => {
        listeners.delete(listener)
      }
    },
  }
}

function mergeSearchFields<Row extends Record<string, unknown>>(
  currentFields: SearchField<Row>[],
  nextFields: SearchField<Row>[]
) {
  const currentFieldById = new Map(
    currentFields.map((field) => [field.id, field] as const)
  )

  return nextFields.map<SearchField<Row>>((field) => {
    const currentField = currentFieldById.get(field.id)

    if (!currentField) {
      return field
    }

    return {
      ...field,
      options:
        field.options || currentField.options
          ? Array.from(
              new Set([...(currentField.options ?? []), ...(field.options ?? [])])
            )
          : undefined,
      sample: field.sample ?? currentField.sample,
    }
  })
}

function getSearchSourceSignature(
  fields: SearchField<Record<string, unknown>>[]
) {
  return JSON.stringify(
    fields.map((field) => ({
      id: field.id,
      kind: field.kind,
      options: field.options ?? null,
      sample: field.sample ?? null,
    }))
  )
}

function getCollectionRows<
  TData,
  TFilters extends Record<string, unknown>,
  TState extends DatoolStateShape,
  TRow extends Record<string, unknown>,
>(
  definition: Extract<
    DatoolQueryDefinition<TData, TFilters, TState, TRow>,
    { kind: "collection" }
  >
) {
  if (definition.getRows) {
    return definition.getRows(definition.result.data)
  }

  return Array.isArray(definition.result.data)
    ? (definition.result.data as TRow[])
    : []
}

function resolveDefaultQueryId(
  datool: InternalDatoolInstance<any>,
  definitions: Record<string, DatoolQueryDefinition<any, any, any, any>>
) {
  const queryEntries = Object.entries(definitions)

  if (queryEntries.length === 0) {
    throw new Error("DatoolProvider requires at least one registered query.")
  }

  if (datool.defaultQuery) {
    if (!definitions[datool.defaultQuery]) {
      throw new Error(`Unknown default datool query "${datool.defaultQuery}".`)
    }

    return datool.defaultQuery
  }

  if (queryEntries.length === 1) {
    return queryEntries[0]![0]
  }

  throw new Error(
    "Datool requires a defaultQuery when more than one query is registered."
  )
}

const DatoolContext = React.createContext<DatoolContextValue | null>(null)

export function useDatool<TState extends DatoolStateShape>({
  defaultQuery,
  initialState,
}: {
  defaultQuery?: Extract<keyof TState, string>
  initialState: TState
}): DatoolInstance<TState> {
  const storeRef = React.useRef<DatoolStore<TState> | null>(null)
  const definitionsRef = React.useRef<
    Record<string, DatoolQueryDefinition<any, any, any, any>>
  >({})
  const sliceCacheRef = React.useRef<
    Partial<Record<Extract<keyof TState, string>, DatoolSliceApi<any>>>
  >({})
  const datoolRef = React.useRef<InternalDatoolInstance<TState> | null>(null)

  if (!storeRef.current) {
    storeRef.current = createDatoolStore(initialState)
  }

  definitionsRef.current = {}

  if (!datoolRef.current) {
    const getStore = () => storeRef.current!
    const ensureSliceKey = (key: string) => {
      if (!Object.prototype.hasOwnProperty.call(getStore().getState(), key)) {
        throw new Error(`Unknown datool state slice "${key}".`)
      }
    }
    const registerDefinition = (
      key: string,
      definition: DatoolQueryDefinition<any, any, any, any>
    ) => {
      ensureSliceKey(key)

      const existing = definitionsRef.current[key]

      if (existing && existing.kind !== definition.kind) {
        throw new Error(
          `Datool query "${key}" is registered with conflicting kinds.`
        )
      }

      definitionsRef.current[key] = definition
    }

    datoolRef.current = {
      __getDefinitions: () => definitionsRef.current,
      defaultQuery,
      slice: (key) => {
        ensureSliceKey(key)

        const cached = sliceCacheRef.current[key]

        if (cached) {
          return cached as DatoolSliceApi<TState[typeof key]>
        }

        const sliceApi = {
          get: () => getStore().getState()[key],
          getInitial: () => getStore().getInitialState()[key],
          set: (update) => {
            getStore().setSlice(key, update as never)
          },
          use: <TSelected,>(selector: (state: TState[typeof key]) => TSelected) =>
            React.useSyncExternalStore(
              getStore().subscribe,
              () => selector(getStore().getState()[key]),
              () => selector(getStore().getInitialState()[key])
            ),
        } satisfies DatoolSliceApi<TState[typeof key]>

        sliceCacheRef.current[key] = sliceApi

        return sliceApi
      },
      useCollection: ({ key, ...definition }) => {
        registerDefinition(key, {
          ...definition,
          kind: "collection",
        } satisfies DatoolCollectionQueryDefinition<any, any, any, any>)
      },
      useEntity: ({ key, ...definition }) => {
        registerDefinition(key, {
          ...definition,
          kind: "entity",
        } satisfies DatoolEntityQueryDefinition<any, any>)
      },
    }
  }

  datoolRef.current.defaultQuery = defaultQuery

  return datoolRef.current
}

export function DatoolProvider({ children, datool }: DatoolProviderProps) {
  const internalDatool = datool as InternalDatoolInstance<any>
  const [viewRevisionByQueryId, setViewRevisionByQueryId] = React.useState<
    Record<string, number>
  >({})
  const [searchSourceByQueryId, setSearchSourceByQueryId] = React.useState<
    Record<string, DatoolSearchSourceValue | undefined>
  >({})

  const resetView = React.useCallback((queryId: string) => {
    setViewRevisionByQueryId((current) => ({
      ...current,
      [queryId]: (current[queryId] ?? 0) + 1,
    }))
  }, [])
  const clearSearchSource = React.useCallback((queryId: string) => {
    setSearchSourceByQueryId((current) => {
      if (!current[queryId]) {
        return current
      }

      const next = { ...current }
      delete next[queryId]
      return next
    })
  }, [])
  const setSearchSource = React.useCallback(
    (queryId: string, source: DatoolSearchSourceValue) => {
      setSearchSourceByQueryId((current) => {
        const existing = current[queryId]
        const mergedFields = mergeSearchFields(
          (existing?.fields ?? []) as SearchField<Record<string, unknown>>[],
          source.fields as SearchField<Record<string, unknown>>[]
        )
        const mergedSignature = getSearchSourceSignature(
          mergedFields as SearchField<Record<string, unknown>>[]
        )

        if (existing?.signature === mergedSignature) {
          return current
        }

        return {
          ...current,
          [queryId]: {
            fields: mergedFields,
            signature: mergedSignature,
          },
        }
      })
    },
    []
  )

  const value = React.useMemo(
    () => ({
      clearSearchSource,
      datool: internalDatool,
      resetView,
      searchSourceByQueryId,
      setSearchSource,
      viewRevisionByQueryId,
    }),
    [
      clearSearchSource,
      internalDatool,
      resetView,
      searchSourceByQueryId,
      setSearchSource,
      viewRevisionByQueryId,
    ]
  )

  return <DatoolContext.Provider value={value}>{children}</DatoolContext.Provider>
}

export function useDatoolContext() {
  const context = React.useContext(DatoolContext)

  if (!context) {
    throw new Error("Datool hooks must be used inside DatoolProvider.")
  }

  return context
}

export function useDatoolQuery<
  TData = unknown,
  TFilters extends Record<string, unknown> = Record<string, unknown>,
  TState extends DatoolStateShape = DatoolStateShape,
  TRow extends Record<string, unknown> = Record<string, unknown>,
>(queryId?: string) {
  const context = useDatoolContext()
  const definitions = context.datool.__getDefinitions()
  const resolvedQueryId = queryId ?? resolveDefaultQueryId(context.datool, definitions)
  const definition = definitions[resolvedQueryId] as
    | DatoolQueryDefinition<TData, TFilters, TState, TRow>
    | undefined

  if (!definition) {
    throw new Error(`Unknown datool query "${resolvedQueryId}".`)
  }

  const state = context.datool.slice(resolvedQueryId as Extract<keyof TState, string>) as
    | DatoolSliceApi<TFilters>
  const filters = state.use((current) => current)
  const rows =
    definition.kind === "collection" ? getCollectionRows(definition) : ([] as TRow[])

  return React.useMemo(
    () =>
      ({
        datool: context.datool,
        definition,
        filters,
        id: resolvedQueryId,
        resetView: () => context.resetView(resolvedQueryId),
        result: definition.result as UseQueryResult<TData>,
        rows,
        state,
        viewRevision: context.viewRevisionByQueryId[resolvedQueryId] ?? 0,
      }) satisfies DatoolQueryValue<TData, TFilters, TState, TRow>,
    [context, definition, filters, resolvedQueryId, rows, state]
  )
}

export function useDatoolCollectionQuery<
  TData = unknown,
  TFilters extends Record<string, unknown> = Record<string, unknown>,
  TState extends DatoolStateShape = DatoolStateShape,
  TRow extends Record<string, unknown> = Record<string, unknown>,
>(queryId?: string) {
  const query = useDatoolQuery<TData, TFilters, TState, TRow>(queryId)

  if (query.definition.kind !== "collection") {
    throw new Error(
      `Datool query "${query.id}" is not a collection query and cannot be used here.`
    )
  }

  return query as DatoolQueryValue<TData, TFilters, TState, TRow> & {
    definition: Extract<
      DatoolQueryDefinition<TData, TFilters, TState, TRow>,
      { kind: "collection" }
    >
  }
}

export function useRegisterDatoolSearchSource<
  TRow extends Record<string, unknown> = Record<string, unknown>,
>() {
  const { setSearchSource } = useDatoolContext()

  return React.useCallback(
    (queryId: string, fields: SearchField<TRow>[]) => {
      setSearchSource(queryId, {
        fields: fields as SearchField<any>[],
        signature: getSearchSourceSignature(
          fields as SearchField<Record<string, unknown>>[]
        ),
      })
    },
    [setSearchSource]
  )
}

export function useClearDatoolSearchSource() {
  const { clearSearchSource } = useDatoolContext()

  return React.useCallback(
    (queryId: string) => {
      clearSearchSource(queryId)
    },
    [clearSearchSource]
  )
}

export function useDatoolSearch<
  TData = unknown,
  TFilters extends Record<string, unknown> = Record<string, unknown>,
  TState extends DatoolStateShape = DatoolStateShape,
  TRow extends Record<string, unknown> = Record<string, unknown>,
>(queryId?: string) {
  const collection = useDatoolCollectionQuery<TData, TFilters, TState, TRow>(queryId)
  const context = useDatoolContext()
  const searchSource = context.searchSourceByQueryId[collection.id]
  const searchKey = collection.definition.searchKey
  const searchValue = collection.state.use((filters) => {
    if (!searchKey) {
      return ""
    }

    const value = filters[searchKey]
    return typeof value === "string" ? value : ""
  })

  const search = React.useMemo<DatoolQuerySearch | undefined>(() => {
    if (!searchKey) {
      return undefined
    }

    return {
      onChange: (next) => {
        collection.state.set({
          [searchKey]: next,
        } as unknown as Partial<TFilters>)
      },
      reset: () => {
        collection.state.set({
          [searchKey]: collection.state.getInitial()[searchKey],
        } as unknown as Partial<TFilters>)
      },
      value: searchValue,
    }
  }, [collection.state, searchKey, searchValue])

  return React.useMemo(
    () => ({
      ...collection,
      search,
      searchFields: (searchSource?.fields ?? []) as SearchField<TRow>[],
    }),
    [collection, search, searchSource]
  )
}

"use client"

import * as React from "react"

import {
  DataTable,
  DataTableProvider,
  type DataTableColumnConfig,
  type DataTableRowAction,
  type DataTableRowActionContext,
} from "@/components/data-table"
import { buildTableSearchFields } from "@/components/data-table/lib/data-table-filters"
import type { SearchField } from "@/components/search-bar"

import {
  useClearDatoolSearchSource,
  useRegisterDatoolSearchSource,
  useDatoolSearch,
} from "./provider"
import type { DatoolQueryActionContext } from "./types"

export type DatoolDataTableProps<
  TRow extends Record<string, unknown> = Record<string, unknown>,
> = {
  columns: DataTableColumnConfig<TRow>[]
  query?: string
  rowClassName?: (row: TRow) => string | undefined
  rowHeight?: number
  rowStyle?: (row: TRow) => React.CSSProperties | undefined
}

function toActionContext<
  TData,
  TFilters extends Record<string, unknown>,
  TState extends Record<string, Record<string, unknown>>,
  TRow extends Record<string, unknown>,
>({
  collection,
  context,
}: {
  collection: ReturnType<typeof useDatoolSearch<TData, TFilters, TState, TRow>>
  context: DataTableRowActionContext<TRow>
}) {
  return {
    actionRowIds: context.actionRowIds,
    actionRows: context.actionRows,
    anchorRow: context.anchorRow ?? null,
    anchorRowId: context.anchorRowId ?? null,
    datool: collection.datool,
    filters: collection.filters,
    queryId: collection.id,
    refetch: collection.result.refetch,
    result: collection.result,
    rows: collection.rows,
    selectedRowIds: context.selectedRowIds,
    selectedRows: context.selectedRows,
    state: collection.state,
  } as DatoolQueryActionContext<TData, TFilters, TState, TRow>
}

function getSearchFieldSignature<TRow extends Record<string, unknown>>(
  fields: SearchField<TRow>[]
) {
  return JSON.stringify(
    fields.map((field) => ({
      id: field.id,
      kind: field.kind,
      options: field.options ?? null,
      sample: field.sample ?? null,
    }))
  )
}

export function DatoolDataTable<
  TData = unknown,
  TFilters extends Record<string, unknown> = Record<string, unknown>,
  TState extends Record<string, Record<string, unknown>> = Record<
    string,
    Record<string, unknown>
  >,
  TRow extends Record<string, unknown> = Record<string, unknown>,
>({
  columns,
  query,
  rowClassName,
  rowHeight = 48,
  rowStyle,
  ...props
}: DatoolDataTableProps<TRow>) {
  const collection = useDatoolSearch<TData, TFilters, TState, TRow>(query)
  const clearSearchSource = useClearDatoolSearchSource()
  const registerSearchSource = useRegisterDatoolSearchSource<TRow>()
  const rowActions = React.useMemo<DataTableRowAction<TRow>[]>(() => {
    const actions = collection.definition.actions ?? []

    return actions.map((action, index) => {
      const disabled = action.disabled
      const hidden = action.hidden
      const label = action.label

      return {
        button: action.button,
        disabled:
          typeof disabled === "function"
            ? (context: DataTableRowActionContext<TRow>) =>
                disabled(
                  toActionContext({
                    collection,
                    context,
                  })
                )
            : disabled,
        hidden:
          typeof hidden === "function"
            ? (context: DataTableRowActionContext<TRow>) =>
                hidden(
                  toActionContext({
                    collection,
                    context,
                  })
                )
            : hidden,
        icon: action.icon,
        id: `query-action-${index}`,
        label:
          typeof label === "function"
            ? (context: DataTableRowActionContext<TRow>) =>
                label(
                  toActionContext({
                    collection,
                    context,
                  })
                )
            : label,
        onSelect: async (context: DataTableRowActionContext<TRow>) => {
          await action.onSelect(
            toActionContext({
              collection,
              context,
            })
          )
        },
        scope: action.scope,
        variant: action.variant,
      }
    })
  }, [collection])
  const enableRowSelection = React.useMemo(
    () => rowActions.some((action) => action.scope === "selection"),
    [rowActions]
  )
  const searchFields = React.useMemo(
    () =>
      buildTableSearchFields(
        columns,
        collection.rows.slice(0, 200)
      ) as SearchField<TRow>[],
    [collection.rows, columns]
  )
  const searchFieldSignature = React.useMemo(
    () => getSearchFieldSignature(searchFields),
    [searchFields]
  )

  React.useEffect(() => {
    registerSearchSource(collection.id, searchFields)
  }, [collection.id, registerSearchSource, searchFieldSignature])

  React.useEffect(() => {
    return () => {
      clearSearchSource(collection.id)
    }
  }, [clearSearchSource, collection.id])

  return (
    <DataTableProvider
      {...props}
      columns={columns}
      data={collection.rows}
      enableRowSelection={enableRowSelection}
      getRowId={collection.definition.getRowId}
      id={`datool-demo-${collection.id}`}
      key={`${collection.id}:${collection.viewRevision}`}
      onSearchChange={collection.search?.onChange}
      rowActions={rowActions}
      rowClassName={rowClassName}
      rowHeight={rowHeight}
      rowStyle={rowStyle}
      search={collection.search?.value}
    >
      <DataTable />
    </DataTableProvider>
  )
}

"use client"

import { RefreshCwIcon, Trash2Icon } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Slot } from "radix-ui"
import { useDatoolQuery } from "./provider"

export function RefreshButton({
  className,
  label = "Refresh data",
  query,
}: {
  className?: string
  label?: string
  query?: string
}) {
  const datoolQuery = useDatoolQuery(query)

  return (
    <Button
      aria-label={label}
      className={className}
      onClick={() => void datoolQuery.result.refetch()}
      size="lg"
      type="button"
      variant="outline"
    >
      <RefreshCwIcon className="size-4" />
    </Button>
  )
}

export function ClearButton({
  className,
  label = "Reset view",
  query,
}: {
  className?: string
  label?: string
  query?: string
}) {
  const datoolQuery = useDatoolQuery(query)
  const searchKey =
    datoolQuery.definition.kind === "collection"
      ? datoolQuery.definition.searchKey
      : undefined
  const canResetSearch = searchKey
    ? !Object.is(
        datoolQuery.filters[searchKey],
        datoolQuery.state.getInitial()[searchKey]
      )
    : false
  const canReset =
    canResetSearch || datoolQuery.viewRevision > 0

  return (
    <Button
      aria-label={label}
      className={className}
      disabled={!canReset}
      onClick={() => {
        if (searchKey) {
          datoolQuery.state.set({
            [searchKey]: datoolQuery.state.getInitial()[searchKey],
          } as Partial<typeof datoolQuery.filters>)
        }
        datoolQuery.resetView()
      }}
      size="lg"
      type="button"
      variant="outline"
    >
      <Trash2Icon className="size-4" />
    </Button>
  )
}

export function ErrorMessage({
  className = "rounded-2xl border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-700",
  query,
  asChild = false,
}: {
  className?: string
  query?: string
  asChild?: boolean
}) {
  const datoolQuery = useDatoolQuery(query)
  const error = datoolQuery.result.error

  if (!error) {
    return null
  }

  const Comp = asChild ? Slot.Root : "div"

  return (
    <Comp className={className}>
      {error instanceof Error ? error.message : String(error)}
    </Comp>
  )
}

"use client"

import { SearchBar as ConnectedSearchBar } from "@/components/search-bar"
import { useDatoolSearch } from "./provider"

export function SearchBar({
  className,
  placeholder = "Search data...",
  query,
}: {
  className?: string
  placeholder?: string
  query?: string
}) {
  const datoolQuery = useDatoolSearch(query)
  const search = datoolQuery.search

  if (!search) {
    return null
  }

  return (
    <ConnectedSearchBar
      className={className}
      fields={datoolQuery.searchFields}
      isLoading={datoolQuery.result.isFetching}
      onSearchChange={search.onChange}
      placeholder={placeholder}
      value={search.value}
    />
  )
}

"use client"

import type { Ref } from "react"

import {
  DataTableSearchInput,
  type DataTableSearchInputHandle,
} from "./search-input"
import type { SearchField } from "./search-core"

export type { SearchField, SearchFieldKind, SearchFieldSpec } from "./search-core"

export type SearchBarHandle = DataTableSearchInputHandle

export type SearchBarProps<Row extends Record<string, unknown>> = {
  className?: string
  fields: SearchField<Row>[]
  inputRef?: Ref<SearchBarHandle>
  isLoading?: boolean
  onSearchChange: (value: string) => void
  placeholder?: string
  value: string
}

/**
 * Controlled token-aware search bar.
 */
export function SearchBar<Row extends Record<string, unknown>>({
  className,
  fields,
  inputRef,
  isLoading,
  onSearchChange,
  placeholder,
  value,
}: SearchBarProps<Row>) {
  return (
    <div className={className ?? "min-w-0 flex-1"}>
      <DataTableSearchInput
        fields={fields}
        inputRef={inputRef}
        isLoading={isLoading}
        onSearchChange={onSearchChange}
        placeholder={placeholder}
        value={value}
      />
    </div>
  )
}

export type SearchFieldKind = "date" | "enum" | "json" | "number" | "text"

export type SearchField<Row> = {
  getValue: (row: Row) => unknown
  id: string
  kind: SearchFieldKind
  options?: string[]
  sample?: string
}

export type SearchFieldSpec = Omit<SearchField<unknown>, "getValue">

export type SearchSuggestion = {
  group: "filters" | "input" | "values"
  id: string
  insertText: string
  keepOpen?: boolean
  label: string
  mode: "append" | "replace-token" | "replace-whole"
}

export type SearchTokenOperator = ":" | "." | "<" | ">"

export type SearchSelectorRange = {
  end: number
  fieldId: string
  operator: SearchTokenOperator
  start: number
  token: string
}

type SearchTokenRange = {
  end: number
  start: number
  token: string
}

type TokenContext<Row> = {
  end: number
  field?: SearchField<Row>
  fragment: string
  operator?: SearchTokenOperator
  start: number
  token: string
}

type MatchedSearchToken<Row> = {
  field?: SearchField<Row>
  fieldId: string
  fragment: string
  operator: SearchTokenOperator
}

function withSuggestionMode(
  suggestion: SearchSuggestion,
  mode: SearchSuggestion["mode"]
): SearchSuggestion {
  return {
    ...suggestion,
    mode,
  }
}

function matchSearchToken<Row>(
  token: string,
  fields: SearchField<Row>[]
): MatchedSearchToken<Row> | null {
  const match = token.match(/^([a-zA-Z0-9_.-]+)(:|>|<|\.)(.*)$/)

  if (!match) {
    return null
  }

  const [, fieldId, operator, fragment] = match

  return {
    field: fields.find((item) => item.id === fieldId),
    fieldId,
    fragment,
    operator: operator as SearchTokenOperator,
  }
}

function isSupportedOperator<Row>(
  field: SearchField<Row>,
  operator: SearchTokenOperator
) {
  switch (field.kind) {
    case "date":
    case "number":
      return operator === ":" || operator === ">" || operator === "<"
    case "json":
      return operator === ":" || operator === "."
    default:
      return operator === ":"
  }
}

function getSearchTokenRanges(value: string) {
  const ranges: SearchTokenRange[] = []
  let tokenStart = -1
  let isQuoted = false
  let isEscaped = false

  for (let index = 0; index < value.length; index += 1) {
    const character = value[index]

    if (tokenStart === -1) {
      if (/\s/.test(character)) {
        continue
      }

      tokenStart = index
    }

    if (isEscaped) {
      isEscaped = false
      continue
    }

    if (character === "\\") {
      isEscaped = true
      continue
    }

    if (character === '"') {
      isQuoted = !isQuoted
      continue
    }

    if (!isQuoted && /\s/.test(character)) {
      ranges.push({
        end: index,
        start: tokenStart,
        token: value.slice(tokenStart, index),
      })
      tokenStart = -1
    }
  }

  if (tokenStart !== -1) {
    ranges.push({
      end: value.length,
      start: tokenStart,
      token: value.slice(tokenStart),
    })
  }

  return ranges
}

export function splitSearchQuery(value: string) {
  return getSearchTokenRanges(value).map((range) => range.token)
}

function unescapeSearchTokenValue(value: string) {
  return value.replace(/\\(["\\])/g, "$1")
}

function unquoteSearchTokenValue(value: string) {
  const trimmedValue = value.trim()

  if (
    trimmedValue.length >= 2 &&
    trimmedValue.startsWith('"') &&
    trimmedValue.endsWith('"')
  ) {
    return unescapeSearchTokenValue(trimmedValue.slice(1, -1))
  }

  return unescapeSearchTokenValue(trimmedValue)
}

export function quoteSearchTokenValue(value: string) {
  if (!value || /[\s"]/u.test(value)) {
    return `"${value.replace(/["\\]/g, "\\$&")}"`
  }

  return value
}

function buildBaseSuggestions<Row>(fields: SearchField<Row>[]) {
  return fields.flatMap<SearchSuggestion>((field) => {
    switch (field.kind) {
      case "date":
      case "number":
        return [
          {
            group: "filters",
            id: `${field.id}-eq`,
            insertText: `${field.id}:`,
            keepOpen: true,
            label: `${field.id}:`,
            mode: "append",
          },
          {
            group: "filters",
            id: `${field.id}-gt`,
            insertText: `${field.id}>`,
            keepOpen: true,
            label: `${field.id}>`,
            mode: "append",
          },
          {
            group: "filters",
            id: `${field.id}-lt`,
            insertText: `${field.id}<`,
            keepOpen: true,
            label: `${field.id}<`,
            mode: "append",
          },
        ]
      case "json":
        return [
          {
            group: "filters",
            id: `${field.id}-dot`,
            insertText: `${field.id}.`,
            keepOpen: true,
            label: `${field.id}.`,
            mode: "append",
          },
          {
            group: "filters",
            id: `${field.id}-eq`,
            insertText: `${field.id}:`,
            keepOpen: true,
            label: `${field.id}:`,
            mode: "append",
          },
        ]
      default:
        return [
          {
            group: "filters",
            id: `${field.id}-eq`,
            insertText: `${field.id}:`,
            keepOpen: true,
            label: `${field.id}:`,
            mode: "append",
          },
        ]
    }
  })
}

function getTokenContext<Row>(
  value: string,
  cursor: number,
  fields: SearchField<Row>[]
): TokenContext<Row> {
  const tokenRange = getSearchTokenRanges(value).find(
    (range) => cursor >= range.start && cursor <= range.end
  )
  const start = tokenRange?.start ?? cursor
  const end = tokenRange?.end ?? cursor
  const token = tokenRange?.token ?? ""
  const match = matchSearchToken(token, fields)

  if (!match) {
    return {
      end,
      fragment: token,
      start,
      token,
    }
  }

  return {
    end,
    field: match.field,
    fragment: match.fragment,
    operator: match.operator,
    start,
    token,
  }
}

export function getSelectorHighlightRanges<Row>(
  value: string,
  fields: SearchField<Row>[]
) {
  const ranges: SearchSelectorRange[] = []

  for (const { end, start, token } of getSearchTokenRanges(value)) {
    const parsedToken = matchSearchToken(token, fields)

    if (!parsedToken?.field) {
      continue
    }

    if (!isSupportedOperator(parsedToken.field, parsedToken.operator)) {
      continue
    }

    ranges.push({
      end,
      fieldId: parsedToken.field.id,
      operator: parsedToken.operator,
      start,
      token,
    })
  }

  return ranges
}

export function getSearchSuggestions<Row>(
  value: string,
  cursor: number,
  fields: SearchField<Row>[]
) {
  const token = getTokenContext(value, cursor, fields)
  const hasTokenFragment = token.fragment.trim().length > 0
  const inputSuggestion = value
    ? [
        {
          group: "input" as const,
          id: "input-value",
          insertText: value,
          label: value,
          mode: "replace-whole" as const,
        },
      ]
    : []

  if (!token.field || !token.operator) {
    const baseSuggestions = buildBaseSuggestions(fields)
    const filteredSuggestions = !token.fragment.trim()
      ? baseSuggestions
      : baseSuggestions.filter((suggestion) =>
          suggestion.label
            .toLowerCase()
            .includes(token.fragment.trim().toLowerCase())
        )

    if (hasTokenFragment) {
      return [
        ...inputSuggestion,
        ...filteredSuggestions.map((suggestion) =>
          withSuggestionMode(suggestion, "replace-token")
        ),
      ]
    }

    return [...inputSuggestion, ...filteredSuggestions]
  }

  if (token.field.kind === "enum" && token.operator === ":") {
    const selectedValue = unquoteSearchTokenValue(token.fragment).toLowerCase()

    if (
      selectedValue &&
      (token.field.options ?? []).some(
        (option) => option.toLowerCase() === selectedValue
      )
    ) {
      return inputSuggestion
    }

    const valueSuggestions = (token.field.options ?? [])
      .filter((option) => option.toLowerCase().includes(selectedValue))
      .map<SearchSuggestion>((option) => ({
        group: "values",
        id: `${token.field.id}-${option}`,
        insertText: `${token.field.id}:${quoteSearchTokenValue(option)}`,
        label: option,
        mode: "replace-token",
      }))

    return [...inputSuggestion, ...valueSuggestions]
  }

  if (token.field.kind === "date") {
    const sample = token.field.sample ?? new Date().toISOString()
    const suggestions = [
      {
        group: "values" as const,
        id: `${token.field.id}-today`,
        insertText: `${token.field.id}${token.operator}today`,
        label: "today",
        mode: "replace-token" as const,
      },
      {
        group: "values" as const,
        id: `${token.field.id}-7d`,
        insertText: `${token.field.id}${token.operator}-7d`,
        label: "-7d",
        mode: "replace-token" as const,
      },
      {
        group: "values" as const,
        id: `${token.field.id}-sample`,
        insertText: `${token.field.id}${token.operator}${sample}`,
        label: sample,
        mode: "replace-token" as const,
      },
    ]

    if (token.operator === ":") {
      suggestions[1] = {
        group: "values",
        id: `${token.field.id}-7d`,
        insertText: `${token.field.id}:>-7d`,
        label: ">-7d",
        mode: "replace-token",
      }
      suggestions[2] = {
        group: "values",
        id: `${token.field.id}-sample`,
        insertText: `${token.field.id}:>${sample}`,
        label: `>${sample}`,
        mode: "replace-token",
      }
    }

    const filteredSuggestions = !token.fragment.trim()
      ? suggestions
      : suggestions.filter((suggestion) =>
          suggestion.label
            .toLowerCase()
            .includes(token.fragment.trim().toLowerCase())
        )

    return [...inputSuggestion, ...filteredSuggestions]
  }

  const filteredSuggestions = buildBaseSuggestions([token.field]).filter(
    (suggestion) =>
      suggestion.label.toLowerCase().includes(token.token.trim().toLowerCase())
  )

  return [...inputSuggestion, ...filteredSuggestions]
}

export function applySuggestionToValue<Row>(
  value: string,
  cursor: number,
  fields: SearchField<Row>[],
  suggestion: SearchSuggestion
) {
  const token = getTokenContext(value, cursor, fields)
  const nextValue =
    suggestion.mode === "replace-whole"
      ? suggestion.insertText
      : suggestion.mode === "append"
        ? `${value.trimEnd()}${value.trim() ? " " : ""}${suggestion.insertText}`
        : `${value.slice(0, token.start)}${suggestion.insertText}${value.slice(token.end)}`
  const nextCursor =
    suggestion.mode === "append"
      ? nextValue.length
      : suggestion.mode === "replace-whole"
        ? suggestion.insertText.length
        : token.start + suggestion.insertText.length

  return {
    keepOpen: Boolean(suggestion.keepOpen),
    selectionStart: nextCursor,
    value: nextValue,
  }
}

import * as React from "react"
import { Extension } from "@tiptap/core"
import Document from "@tiptap/extension-document"
import Paragraph from "@tiptap/extension-paragraph"
import Placeholder from "@tiptap/extension-placeholder"
import Text from "@tiptap/extension-text"
import { EditorContent, useEditor, type Editor } from "@tiptap/react"
import { Plugin, PluginKey, TextSelection } from "@tiptap/pm/state"
import { Decoration, DecorationSet } from "@tiptap/pm/view"
import { LoaderCircle, Search, XIcon } from "lucide-react"
import {
  applySuggestionToValue,
  getSearchSuggestions,
  getSelectorHighlightRanges,
  type SearchField as DataTableSearchField,
  type SearchSuggestion as DataTableSearchSuggestion,
} from "./search-core"

export type DataTableSearchInputHandle = {
  focus: () => void
  selectAll: () => void
}

type ControlledDataTableSearchInputProps<Row> = {
  fields: DataTableSearchField<Row>[]
  onSearchChange: (value: string) => void
  value: string
}

export type DataTableSearchInputProps<Row> = {
  inputRef?: React.Ref<DataTableSearchInputHandle>
  isLoading?: boolean
  placeholder?: string
} & ControlledDataTableSearchInputProps<Row>

const selectorPluginKey = new PluginKey(
  "data-table-search-selector-highlighter"
)
const selectorRefreshKey = "refresh-data-table-search-selector-highlighter"
const selectorHighlighterState = {
  fields: [] as DataTableSearchField<unknown>[],
}

function createSelectorDecorations(doc: Editor["state"]["doc"]) {
  const ranges = getSelectorHighlightRanges(
    getPlainText(doc),
    selectorHighlighterState.fields
  )

  return DecorationSet.create(
    doc,
    ranges
      .map((range) => {
        const from = textOffsetToDocPosition(doc, range.start)
        const to = textOffsetToDocPosition(doc, range.end)

        if (from >= to) {
          return null
        }

        return Decoration.inline(
          from,
          to,
          {
            class: "data-table-search-input-selector-token",
            "data-table-search-selector": "",
          },
          {
            inclusiveEnd: false,
            inclusiveStart: false,
          }
        )
      })
      .filter((decoration): decoration is Decoration => decoration !== null)
  )
}

const DataTableSelectorHighlighter = Extension.create({
  name: "dataTableSelectorHighlighter",
  addProseMirrorPlugins() {
    return [
      new Plugin({
        key: selectorPluginKey,
        state: {
          init: (_, state) => createSelectorDecorations(state.doc),
          apply: (transaction, decorationSet, _oldState, newState) => {
            if (
              transaction.docChanged ||
              transaction.getMeta(selectorRefreshKey)
            ) {
              return createSelectorDecorations(newState.doc)
            }

            return decorationSet.map(transaction.mapping, transaction.doc)
          },
        },
        props: {
          decorations(state) {
            return selectorPluginKey.getState(state)
          },
        },
      }),
    ]
  },
})

function assignRefValue<T>(ref: React.Ref<T> | undefined, value: T | null) {
  if (typeof ref === "function") {
    ref(value)
    return
  }

  if (ref) {
    ref.current = value
  }
}

function createEditorDocument(value: string) {
  return {
    content: value
      ? [
          {
            content: [
              {
                text: value,
                type: "text",
              },
            ],
            type: "paragraph",
          },
        ]
      : [
          {
            type: "paragraph",
          },
        ],
    type: "doc",
  } as const
}

function getPlainText(doc: Editor["state"]["doc"]) {
  return doc.textBetween(0, doc.content.size, "", "")
}

function getCursorOffset(editor: Editor) {
  return editor.state.doc.textBetween(0, editor.state.selection.from, "", "")
    .length
}

function textOffsetToDocPosition(doc: Editor["state"]["doc"], offset: number) {
  const totalLength = getPlainText(doc).length
  const clampedOffset = Math.max(0, Math.min(offset, totalLength))
  let remaining = clampedOffset
  let position = TextSelection.atStart(doc).from

  doc.descendants((node, pos) => {
    if (!node.isText) {
      return true
    }

    const text = node.text ?? ""

    if (remaining <= text.length) {
      position = pos + remaining
      return false
    }

    remaining -= text.length
    position = pos + text.length

    return true
  })

  return position
}

function normalizeSingleLineText(value: string) {
  return value.replace(/\r\n?/g, "\n").replace(/\n/g, " ")
}

function moveActiveIndex(
  currentIndex: number,
  totalItems: number,
  direction: 1 | -1
) {
  if (totalItems <= 0) {
    return -1
  }

  if (currentIndex < 0) {
    return direction === 1 ? 0 : totalItems - 1
  }

  return (currentIndex + direction + totalItems) % totalItems
}

export function DataTableSearchInput<Row extends Record<string, unknown>>({
  fields,
  inputRef,
  isLoading = false,
  onSearchChange,
  placeholder = "Search table...",
  value,
}: DataTableSearchInputProps<Row>) {
  const containerRef = React.useRef<HTMLDivElement | null>(null)
  const itemRefs = React.useRef<Array<HTMLButtonElement | null>>([])
  const valueRef = React.useRef(value ?? "")
  const openRef = React.useRef(false)
  const activeIndexRef = React.useRef(-1)
  const suppressNextFocusOpenRef = React.useRef(false)
  const latestSuggestionsRef = React.useRef<DataTableSearchSuggestion[]>([])
  const applySuggestionRef = React.useRef<
    (
      editorInstance: Editor | null,
      suggestion: DataTableSearchSuggestion
    ) => void
  >(() => {})
  const pendingSelectionRef = React.useRef<{
    end: number
    start: number
  } | null>(null)
  const [cursor, setCursor] = React.useState(0)
  const [open, setOpen] = React.useState(false)
  const [activeIndex, setActiveIndex] = React.useState(-1)

  const setActiveSuggestionIndex = React.useCallback((nextIndex: number) => {
    activeIndexRef.current = nextIndex
    setActiveIndex(nextIndex)
  }, [])

  const suggestions = React.useMemo(
    () => getSearchSuggestions(value, cursor, fields),
    [cursor, fields, value]
  )
  const inputSuggestions = React.useMemo(
    () => suggestions.filter((suggestion) => suggestion.group === "input"),
    [suggestions]
  )
  const valueSuggestions = React.useMemo(
    () => suggestions.filter((suggestion) => suggestion.group === "values"),
    [suggestions]
  )
  const filterSuggestions = React.useMemo(
    () => suggestions.filter((suggestion) => suggestion.group === "filters"),
    [suggestions]
  )

  const syncEditorValue = React.useCallback(
    (
      editorInstance: Editor,
      nextValue: string,
      selection?: {
        end: number
        start: number
      }
    ) => {
      editorInstance.commands.setContent(createEditorDocument(nextValue), {
        emitUpdate: false,
        parseOptions: { preserveWhitespace: "full" },
      })

      if (selection) {
        editorInstance.commands.setTextSelection({
          from: textOffsetToDocPosition(
            editorInstance.state.doc,
            selection.start
          ),
          to: textOffsetToDocPosition(editorInstance.state.doc, selection.end),
        })
      }
    },
    []
  )

  const applySuggestion = React.useCallback(
    (editorInstance: Editor | null, suggestion: DataTableSearchSuggestion) => {
      const nextState = applySuggestionToValue(
        value,
        cursor,
        fields,
        suggestion
      )

      pendingSelectionRef.current = {
        end: nextState.selectionStart,
        start: nextState.selectionStart,
      }
      setCursor(nextState.selectionStart)
      setOpen(nextState.keepOpen)

      if (!nextState.keepOpen) {
        suppressNextFocusOpenRef.current = true
      }

      if (editorInstance) {
        syncEditorValue(
          editorInstance,
          nextState.value,
          pendingSelectionRef.current
        )
        editorInstance.commands.focus()
      }

      onSearchChange(nextState.value)
    },
    [cursor, fields, onSearchChange, syncEditorValue, value]
  )

  const editor = useEditor(
    {
      content: createEditorDocument(value),
      editorProps: {
        attributes: {
          autocapitalize: "off",
          autocomplete: "off",
          autocorrect: "off",
          class:
            "data-table-search-input-editor min-w-0 flex-1 overflow-x-auto px-2 py-0 text-sm outline-none whitespace-pre",
          spellcheck: "false",
        },
        handleKeyDown: (_view, event) => {
          if (event.key === "Escape") {
            event.preventDefault()
            suppressNextFocusOpenRef.current = true
            setOpen(false)
            return true
          }

          if (event.key === "ArrowDown") {
            event.preventDefault()
            setOpen(true)
            setActiveSuggestionIndex(
              moveActiveIndex(
                activeIndexRef.current,
                latestSuggestionsRef.current.length,
                1
              )
            )
            return true
          }

          if (event.key === "ArrowUp") {
            event.preventDefault()
            setOpen(true)
            setActiveSuggestionIndex(
              moveActiveIndex(
                activeIndexRef.current,
                latestSuggestionsRef.current.length,
                -1
              )
            )
            return true
          }

          if (event.key === "Tab") {
            const activeSuggestion =
              latestSuggestionsRef.current[activeIndexRef.current]

            if (!openRef.current || !activeSuggestion) {
              return false
            }

            event.preventDefault()
            applySuggestionRef.current(editor, activeSuggestion)
            return true
          }

          if (event.key === "Enter") {
            event.preventDefault()
            event.stopPropagation()

            const activeSuggestion =
              latestSuggestionsRef.current[activeIndexRef.current]

            if (openRef.current && activeSuggestion) {
              applySuggestionRef.current(editor, activeSuggestion)
            } else {
              setCursor(getCursorOffset(editor))
            }

            return true
          }

          return false
        },
        handlePaste: (view, event) => {
          const pastedText = event.clipboardData?.getData("text/plain")

          if (typeof pastedText !== "string") {
            return false
          }

          event.preventDefault()
          view.dispatch(
            view.state.tr.insertText(
              normalizeSingleLineText(pastedText),
              view.state.selection.from,
              view.state.selection.to
            )
          )
          return true
        },
      },
      extensions: [
        Document,
        Paragraph,
        Text,
        Placeholder.configure({
          placeholder,
        }),
        DataTableSelectorHighlighter,
        Extension.create({
          name: "singleLineSearchBehavior",
          addKeyboardShortcuts() {
            return {
              Enter: () => true,
            }
          },
        }),
      ],
      immediatelyRender: false,
      onSelectionUpdate: ({ editor: nextEditor }) => {
        setCursor(getCursorOffset(nextEditor))
      },
      onUpdate: ({ editor: nextEditor }) => {
        const nextValue = getPlainText(nextEditor.state.doc)

        setCursor(getCursorOffset(nextEditor))

        if (nextValue !== valueRef.current) {
          onSearchChange(nextValue)
        }

        setOpen(true)
      },
    },
    []
  )

  React.useEffect(() => {
    valueRef.current = value
  }, [value])

  React.useEffect(() => {
    openRef.current = open
  }, [open])

  React.useEffect(() => {
    activeIndexRef.current = activeIndex
  }, [activeIndex])

  React.useEffect(() => {
    latestSuggestionsRef.current = suggestions
  }, [suggestions])

  React.useEffect(() => {
    applySuggestionRef.current = applySuggestion
  }, [applySuggestion])

  React.useEffect(() => {
    itemRefs.current.length = suggestions.length
  }, [suggestions.length])

  React.useEffect(() => {
    selectorHighlighterState.fields = fields as DataTableSearchField<unknown>[]
  }, [fields])

  React.useEffect(() => {
    if (!editor) {
      return
    }

    editor.view.dispatch(editor.state.tr.setMeta(selectorRefreshKey, true))
  }, [editor, fields])

  React.useEffect(() => {
    if (!editor) {
      return
    }

    const nextSelection = pendingSelectionRef.current
    const editorValue = getPlainText(editor.state.doc)

    if (editorValue !== value) {
      syncEditorValue(editor, value, nextSelection ?? undefined)
    } else if (nextSelection) {
      editor.commands.setTextSelection({
        from: textOffsetToDocPosition(editor.state.doc, nextSelection.start),
        to: textOffsetToDocPosition(editor.state.doc, nextSelection.end),
      })
    }

    pendingSelectionRef.current = null
    setCursor(getCursorOffset(editor))
  }, [editor, syncEditorValue, value])

  React.useEffect(() => {
    const nextCursor = Math.min(cursor, value.length)

    if (nextCursor !== cursor) {
      setCursor(nextCursor)
    }
  }, [cursor, value.length])

  React.useEffect(() => {
    const nextIndex =
      suggestions.length > 0
        ? Math.min(activeIndex, suggestions.length - 1)
        : -1

    setActiveSuggestionIndex(open ? nextIndex : -1)
  }, [activeIndex, open, setActiveSuggestionIndex, suggestions.length])

  React.useEffect(() => {
    if (!open || activeIndex < 0) {
      return
    }

    itemRefs.current[activeIndex]?.scrollIntoView({
      block: "nearest",
    })
  }, [activeIndex, open])

  React.useEffect(() => {
    const handlePointerDown = (event: PointerEvent) => {
      if (!containerRef.current?.contains(event.target as Node)) {
        setOpen(false)
      }
    }

    window.addEventListener("pointerdown", handlePointerDown)

    return () => window.removeEventListener("pointerdown", handlePointerDown)
  }, [])

  React.useEffect(() => {
    if (!inputRef) {
      return
    }

    assignRefValue(inputRef, {
      focus: () => {
        editor?.commands.focus()
      },
      selectAll: () => {
        editor?.chain().focus().selectAll().run()
      },
    })

    return () => assignRefValue(inputRef, null)
  }, [editor, inputRef])

  const showLoading = isLoading
  const groupedSuggestions = [
    { items: inputSuggestions, label: undefined },
    { items: valueSuggestions, label: "Values" },
    { items: filterSuggestions, label: "Filters" },
  ] satisfies Array<{
    items: DataTableSearchSuggestion[]
    label?: string
  }>

  let flatIndex = 0

  return (
    <div ref={containerRef} className="min-w-64 relative flex-1">
      <div className="border-input bg-background ring-offset-background focus-within:border-ring focus-within:ring-ring/30 flex h-10 w-full items-center rounded-md border text-lg focus-within:ring-2">
        <div className="flex shrink-0 items-center pl-3">
          <span
            aria-hidden="true"
            className="size-5 flex shrink-0 items-center justify-center"
          >
            {showLoading ? (
              <LoaderCircle className="size-4.5 animate-spin" />
            ) : (
              <Search className="size-4.5" />
            )}
          </span>
        </div>
        <div className="min-w-0 flex-1">
          <EditorContent
            editor={editor}
            onBlur={() => {
              requestAnimationFrame(() => {
                if (!containerRef.current?.contains(document.activeElement)) {
                  setOpen(false)
                }
                suppressNextFocusOpenRef.current = false
              })
            }}
            onClick={() => {
              setCursor(editor ? getCursorOffset(editor) : 0)
              suppressNextFocusOpenRef.current = false
              setOpen(true)
            }}
            onFocus={() => {
              setCursor(editor ? getCursorOffset(editor) : 0)

              if (suppressNextFocusOpenRef.current) {
                suppressNextFocusOpenRef.current = false
                return
              }

              setOpen(true)
            }}
          />
        </div>
        <div className="flex shrink-0 items-center pr-1">
          {value ? (
            <button
              aria-label="Clear search"
              className="text-muted-foreground hover:bg-accent hover:text-accent-foreground inline-flex size-7 items-center justify-center rounded-md transition-colors"
              onClick={() => {
                if (!editor) {
                  onSearchChange("")
                  setCursor(0)
                  setOpen(false)
                  return
                }

                pendingSelectionRef.current = { end: 0, start: 0 }
                setCursor(0)
                setOpen(false)
                syncEditorValue(editor, "", pendingSelectionRef.current)
                editor.commands.focus()
                onSearchChange("")
              }}
              type="button"
            >
              <XIcon className="pointer-events-none" />
            </button>
          ) : null}
        </div>
      </div>

      {open ? (
        <div className="left-0 mt-1 absolute top-full z-50 w-full">
          <div className="max-h-[min(calc(var(--spacing(72)---spacing(9)),calc(100svh---spacing(20)))] rounded-lg bg-popover text-popover-foreground shadow-md ring-foreground/10 overflow-hidden ring-1">
            {suggestions.length === 0 ? (
              <div className="py-2 text-xs/relaxed text-muted-foreground flex w-full justify-center text-center">
                No items found.
              </div>
            ) : (
              <div className="max-h-[min(calc(var(--spacing(72)---spacing(9)),calc(100svh---spacing(20)))] p-1 overflow-y-auto">
                {groupedSuggestions.map((group) => {
                  if (group.items.length === 0) {
                    return null
                  }

                  return (
                    <div key={group.label ?? "Input"}>
                      {group.label ? (
                        <div className="px-2 py-1.5 text-xs text-muted-foreground">
                          {group.label}
                        </div>
                      ) : null}
                      {group.items.map((item) => {
                        const itemIndex = flatIndex

                        flatIndex += 1

                        return (
                          <button
                            key={item.id}
                            ref={(node) => {
                              itemRefs.current[itemIndex] = node
                            }}
                            type="button"
                            className={`min-h-7 gap-2 rounded-md px-2 py-1 text-xs/relaxed hover:bg-accent hover:text-accent-foreground relative flex w-full cursor-default items-center text-left outline-hidden select-none ${
                              itemIndex === activeIndex
                                ? "bg-accent text-accent-foreground"
                                : ""
                            }`}
                            data-highlighted={
                              itemIndex === activeIndex ? "" : undefined
                            }
                            onClick={() => applySuggestion(editor, item)}
                            onMouseDown={(event) => {
                              event.preventDefault()
                            }}
                            onMouseEnter={() =>
                              setActiveSuggestionIndex(itemIndex)
                            }
                          >
                            <span className="truncate">{item.label}</span>
                          </button>
                        )
                      })}
                    </div>
                  )
                })}
              </div>
            )}
          </div>
        </div>
      ) : null}
    </div>
  )
}

export const DataTableSearch = DataTableSearchInput
